import React, { useRef } from 'react';
import { Card } from './ui/card';
import { Button } from './ui/button';
import { Badge } from './ui/badge';
import { Github, ExternalLink, Bot, Mic, Briefcase, MessageSquare, ChevronLeft, ChevronRight } from 'lucide-react';
import { motion } from 'framer-motion';

const Projects = () => {
  const projects = [
    {
      title: 'CortexAI – AI Powered Chatbot',
      description: 'Built a full-stack AI chatbot using Gemini API with Clerk authentication and MongoDB for chat history. Designed a responsive UI with Tailwind CSS and deployed on Vercel for global access.',
      icon: <MessageSquare size={40} />,
      tech: ['React', 'Next.js', 'MongoDB', 'Tailwind CSS', 'Gemini API', 'Clerk'],
      github: 'https://github.com/FAYAZKLU',
      demo: '#',
    },
    {
      title: 'Interview Buddy – AI Interview Mocker',
      description: 'Developed a mock interview app with AI-generated questions, voice recording, and webcam monitoring. Implemented feedback, ratings, and answer validation using Gemini API.',
      icon: <Bot size={40} />,
      tech: ['Next.js', 'React', 'Clerk', 'Drizzle ORM', 'Gemini API'],
      github: 'https://github.com/FAYAZKLU',
      demo: '#',
    },
    {
      title: 'Nexora - AI Virtual Assistant',
      description: 'Created a voice-controlled virtual assistant using Gemini and Web Speech APIs for real-time responses and voice synthesis. Designed an interactive and responsive UI.',
      icon: <Mic size={40} />,
      tech: ['React.js', 'Web Speech API', 'Gemini API', 'JavaScript'],
      github: 'https://github.com/FAYAZKLU',
      demo: '#',
    },
    {
      title: 'Automated Job Search Agent',
      description: 'Designed an n8n workflow that fetches job data from Sheets, filters LinkedIn jobs by resume score, and sends Telegram alerts for scores more than 60, automating job tracking.',
      icon: <Briefcase size={40} />,
      tech: ['n8n', 'Google Sheets API', 'Telegram Bot API', 'LinkedIn Scraper'],
      github: 'https://github.com/FAYAZKLU',
      demo: '#',
    },
  ];

  const sliderRef = useRef(null);

  const scrollByPage = (direction = 1) => {
    const el = sliderRef.current;
    if (!el) return;
    const amount = el.clientWidth * direction;
    el.scrollBy({ left: amount, behavior: 'smooth' });
  };

  return (
    <motion.section
      id="projects"
      className="py-20 bg-black"
      initial={{ opacity: 0, y: 30 }}
      whileInView={{ opacity: 1, y: 0 }}
      viewport={{ once: true, amount: 0.2 }}
      transition={{ duration: 0.6, ease: 'easeOut' }}
    >
      <div className="container mx-auto px-6">
        <div className="max-w-6xl mx-auto">
          <div className="mb-10">
            <h2 className="text-4xl md:text-5xl font-bold text-white mb-2">Featured Projects</h2>
            <div className="w-20 h-1 bg-white/40 mb-2"></div>
            <p className="text-white/60 text-lg">Slide to explore each project</p>
          </div>

          <div className="relative">
            {/* Arrows */}
            <div className="absolute inset-y-0 left-0 flex items-center">
              <button
                aria-label="Previous"
                onClick={() => scrollByPage(-1)}
                className="hidden md:flex h-10 w-10 items-center justify-center rounded-full bg-white/90 shadow hover:shadow-md border border-sage/30 text-forest hover:text-sage transition-all -ml-3"
              >
                <ChevronLeft size={18} />
              </button>
            </div>
            <div className="absolute inset-y-0 right-0 flex items-center">
              <button
                aria-label="Next"
                onClick={() => scrollByPage(1)}
                className="hidden md:flex h-10 w-10 items-center justify-center rounded-full bg-white/90 shadow hover:shadow-md border border-sage/30 text-forest hover:text-sage transition-all -mr-3"
              >
                <ChevronRight size={18} />
              </button>
            </div>

            {/* Slider viewport */}
            <div
              ref={sliderRef}
              className="overflow-x-auto scroll-smooth snap-x snap-mandatory rounded-2xl"
            >
              <div className="flex">
                {projects.map((project, index) => (
                  <div
                    key={index}
                    className="snap-start shrink-0 w-full p-2 md:p-3"
                  >
                    <motion.div
                      className="h-full"
                      initial={{ y: 6, opacity: 0 }}
                      whileInView={{ y: 0, opacity: 1 }}
                      viewport={{ once: true, amount: 0.3 }}
                      transition={{ duration: 0.5, ease: 'easeOut' }}
                      whileHover={{ y: -6, boxShadow: '0 18px 40px rgba(0,0,0,0.35)' }}
                    >
                      <Card className="h-full bg-white/10 backdrop-blur-md border border-white/15 hover:border-white/30 transition-all duration-300 group overflow-hidden">
                        <div className="p-6">
                          <div className="mb-4 text-white/80 group-hover:text-white transition-colors">{project.icon}</div>
                          <h3 className="text-2xl font-bold text-white mb-3">
                            {project.title}
                          </h3>
                          <p className="text-white/70 mb-4 leading-relaxed">{project.description}</p>
                          <div className="flex flex-wrap gap-2 mb-6">
                            {project.tech.map((tech, techIndex) => (
                              <Badge key={techIndex} variant="outline" className="bg-white/5 border-white/20 text-white/80 hover:bg-white/10 hover:text-white transition-colors">
                                {tech}
                              </Badge>
                            ))}
                          </div>
                          <div className="flex gap-3">
                            <Button
                              variant="outline"
                              size="sm"
                              className="border-white/30 text-white hover:bg-white/10 hover:text-white transition-all"
                              onClick={() => window.open(project.github, '_blank')}
                            >
                              <Github size={16} className="mr-2" />
                              Code
                            </Button>
                            <Button
                              size="sm"
                              className="bg-white/15 hover:bg-white/25 text-white transition-all"
                              onClick={() => window.open(project.demo !== '#' ? project.demo : project.github, '_blank')}
                            >
                              <ExternalLink size={16} className="mr-2" />
                              View My Project
                            </Button>
                          </div>
                        </div>
                        <div className="h-1 bg-white/30 transform scale-x-0 group-hover:scale-x-100 transition-transform duration-300 origin-left"></div>
                      </Card>
                    </motion.div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>
      </div>
    </motion.section>
  );
};

export default Projects;
